   141→func RoleAppPluginAuth(accessControl ac.AccessControl, ps pluginstore.Store, logger log.Logger) func(c *contextmodel.ReqContext) {
   142→	return func(c *contextmodel.ReqContext) {
   143→		pluginID := web.Params(c.Req)[":id"]
   144→		p, exists := ps.Plugin(c.Req.Context(), pluginID)
   145→		if !exists {
   146→			// The frontend will handle app not found appropriately
   147→			return
   148→		}
   149→
   150→		permitted := true
   151→		path := normalizeIncludePath(c.Req.URL.Path)
   152→		hasAccess := ac.HasAccess(accessControl, c)
   153→		for _, i := range p.Includes {
   154→			if i.Type != "page" {
   155→				continue
   156→			}
   157→
   158→			u, err := url.Parse(i.Path)
   159→			if err != nil {
   160→				logger.Error("failed to parse include path", "pluginId", pluginID, "include", i.Name, "err", err)
   161→				continue
   162→			}
   163→
   164→			if normalizeIncludePath(u.Path) == path {
   165→				if i.RequiresRBACAction() && !hasAccess(pluginaccesscontrol.GetPluginRouteEvaluator(pluginID, i.Action)) {
   166→					logger.Debug("Plugin include is covered by RBAC, user doesn't have access", "plugin", pluginID, "include", i.Name)
   167→					permitted = false
   168→					break
   169→				} else if !i.RequiresRBACAction() && !c.HasUserRole(i.Role) {
   170→					permitted = false
   171→					break
   172→				}
   173→			}
   174→		}
   175→
   176→		if !permitted {
   177→			accessForbidden(c)
   178→			return
   179→		}
   180→	}
   181→}
