   202→func Auth(options *AuthOptions) web.Handler {
   203→	return func(c *contextmodel.ReqContext) {
   204→		forceLogin := false
   205→		if c.AllowAnonymous {
   206→			forceLogin = shouldForceLogin(c)
   207→			if !forceLogin {
   208→				orgIDValue := c.Req.URL.Query().Get("orgId")
   209→				orgID, err := strconv.ParseInt(orgIDValue, 10, 64)
   210→				if err == nil && orgID > 0 && orgID != c.GetOrgID() {
   211→					forceLogin = true
   212→				}
   213→			}
   214→		}
   215→
   216→		requireLogin := !c.AllowAnonymous || forceLogin || options.ReqNoAnonynmous
   217→
   218→		if !c.IsSignedIn && options.ReqSignedIn && requireLogin {
   219→			var revokedErr *auth.TokenRevokedError
   220→			if errors.As(c.LookupTokenErr, &revokedErr) {
   221→				tokenRevoked(c, revokedErr)
   222→				return
   223→			}
   224→
   225→			notAuthorized(c)
   226→			return
   227→		}
   228→
   229→		if !c.IsGrafanaAdmin && options.ReqGrafanaAdmin {
   230→			accessForbidden(c)
   231→			return
   232→		}
   233→	}
   234→}
